import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { FaCamera, FaBars, FaTimes } from "react-icons/fa";
import axios from "axios";

const Navbar = () => {
  const [menuOpen, setMenuOpen] = useState(false);
  const [categoriesBySection, setCategoriesBySection] = useState({});

  const sections = [
    "Photography",
    "Weddings",
    "Editorial Beauty",
    "Fashion",
    "Events"
  ];

  useEffect(() => {
    const fetchAllCategories = async () => {
      const newCategories = {};
      for (const section of sections) {
        try {
          const res = await axios.get(`http://localhost:5000/api/categories?section=${section}`);
          newCategories[section] = res.data;
        } catch (err) {
          console.error(`Failed to load categories for ${section}`, err);
        }
      }
      setCategoriesBySection(newCategories);
    };

    fetchAllCategories();
  }, []);

  const renderDropdown = (section) => (
    <div className="relative group">
      <Link to={`/${section.toLowerCase().replace(/\s+/g, '-')}`} className="hover:text-yellow-500">
        {section}
      </Link>
      {categoriesBySection[section] && (
        <div className="absolute left-0 mt-2 w-48 bg-black text-white rounded shadow-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300 z-50">
          {categoriesBySection[section].map((cat) => (
            <Link
              key={cat.id}
              to={`/${section.toLowerCase().replace(/\s+/g, '-')}/${cat.name.toLowerCase().replace(/\s+/g, '-')}`}
              className="block px-4 py-2 hover:bg-gray-800"
            >
              {cat.name}
            </Link>
          ))}
        </div>
      )}
    </div>
  );

  return (
    <nav className="bg-black text-white p-4 shadow-md fixed w-full top-0 z-50">
      <div className="container mx-auto flex justify-between items-center">
        <Link to="/" className="text-xl font-bold flex items-center">
          <FaCamera className="mr-2" /> JBS Studios
        </Link>

        <div className="hidden md:flex space-x-8 text-sm uppercase tracking-wide">
          <Link to="/" className="hover:text-yellow-500">Home</Link>
          {sections.map((section) => renderDropdown(section))}
          <Link to="/pricing" className="hover:text-yellow-500">Pricing</Link>
          <Link to="/contact" className="hover:text-yellow-500">Contact</Link>
          <Link to="/education" className="hover:text-yellow-500">Education</Link>
          <Link to="/shop" className="hover:text-yellow-500">Shop</Link>
          <Link to="/bio" className="hover:text-yellow-500">Bio</Link>
        </div>

        <button
          className="md:hidden text-white text-2xl focus:outline-none"
          onClick={() => setMenuOpen(!menuOpen)}
        >
          {menuOpen ? <FaTimes /> : <FaBars />}
        </button>
      </div>

      {menuOpen && (
        <div className="md:hidden bg-black p-4 space-y-4 text-center">
          <Link to="/" className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>Home</Link>
          {sections.map((section) => (
            <div key={section}>
              <Link to={`/${section.toLowerCase().replace(/\s+/g, '-')}`} className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>
                {section}
              </Link>
              {categoriesBySection[section]?.map((cat) => (
                <Link
                  key={cat.id}
                  to={`/${section.toLowerCase().replace(/\s+/g, '-')}/${cat.name.toLowerCase().replace(/\s+/g, '-')}`}
                  className="block ml-4 text-sm hover:text-yellow-300"
                  onClick={() => setMenuOpen(false)}
                >
                  {cat.name}
                </Link>
              ))}
            </div>
          ))}
          <Link to="/pricing" className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>Pricing</Link>
          <Link to="/contact" className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>Contact</Link>
          <Link to="/education" className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>Education</Link>
          <Link to="/shop" className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>Shop</Link>
          <Link to="/bio" className="block hover:text-yellow-500" onClick={() => setMenuOpen(false)}>Bio</Link>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
